<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***CacheManagerforSPRIN*File-basedandMemory-basedcachingsystem*/classCacheManager{private$cachePath;private$defaultTTL;private$memoryCache;publicfunction__construct($cachePath=__DIR__.'/../cache/',$defaultTTL=300){$this->cachePath=$cachePath;$this->defaultTTL=$defaultTTL;$this->memoryCache=[];/Createcachedirectoryifnotexistsif(!is_dir($this->cachePath)){mkdir($this->cachePath,0755,true);}}/***Generatecachekey*/privatefunctiongenerateKey($key){returnmd5($key);}/***Getcachefilepath*/privatefunctiongetCacheFile($key){return$this->cachePath.$this->generateKey($key).'.cache';}/***Storedataincache*/publicfunctionset($key,$data,$ttl=null){$ttl=$ttl??$this->defaultTTL;$cacheFile=$this->getCacheFile($key);$cacheData=['expires'=>time()+$ttl,'data'=>$data];/Storeinmemoryforfasteraccess$this->memoryCache[$key]=$cacheData;/Storeinfilefile_put_contents($cacheFile,serialize($cacheData),LOCK_EX);returntrue;}/***Getdatafromcache*/publicfunctionget($key){/Checkmemorycachefirstif(isset($this->memoryCache[$key])){if($this->memoryCache[$key]['expires']>time()){return$this->memoryCache[$key]['data'];}else{unset($this->memoryCache[$key]);returnnull;}}/Checkfilecache$cacheFile=$this->getCacheFile($key);if(!file_exists($cacheFile)){returnnull;}$cacheData=unserialize(file_get_contents($cacheFile));if($cacheData['expires']<time()){unlink($cacheFile);returnnull;}/Storeinmemoryforfasterfutureaccess$this->memoryCache[$key]=$cacheData;return$cacheData['data'];}/***Checkifkeyexistsincache*/publicfunctionhas($key){return$this->get($key)!==null;}/***Deletecacheentry*/publicfunctiondelete($key){unset($this->memoryCache[$key]);$cacheFile=$this->getCacheFile($key);if(file_exists($cacheFile)){returnunlink($cacheFile);}returntrue;}/***Clearallcache*/publicfunctionclear(){$this->memoryCache=[];$files=glob($this->cachePath.'*.cache');forforeach($filesas$file){unlink($file);}returntrue;}/***Getcachestatistics*/publicfunctiongetStats(){$files=glob($this->cachePath.'*.cache');$totalSize=0;$validCount=0;$expiredCount=0;forforeach($filesas$file){$size=filesize($file);$totalSize+=$size;$data=unserialize(file_get_contents($file));if($data['expires']>time()){$validCount++;}else{$expiredCount++;}}return['total_files'=>count($files),'valid_entries'=>$validCount,'expired_entries'=>$expiredCount,'memory_entries'=>count($this->memoryCache),'total_size_bytes'=>$totalSize,'total_size_mb'=>round($totalSize/1024/1024,2)];}/***Cachedatabasequeryresult*/publicfunctionremember($key,$callback,$ttl=null){$cached=$this->get($key);if($cached!==null){return$cached;}$data=$callback();$this->set($key,$data,$ttl);return$data;}/***Deletecachebypattern*/publicfunctiondeletePattern($pattern){$files=glob($this->cachePath.'*.cache');$deleted=0;forforeach($filesas$file){$content=unserialize(file_get_contents($file));/Note:Thisisasimpleimplementation,couldbeenhancedif(strpos(serialize($content['data']),$pattern)!==false){unlink($file);$deleted++;}}return$deleted;}/***Cleanexpiredcacheentries*/publicfunctioncleanExpired(){$files=glob($this->cachePath.'*.cache');$cleaned=0;forforeach($filesas$file){$data=unserialize(file_get_contents($file));if($data['expires']<time()){unlink($file);$cleaned++;}}return$cleaned;}}/***QueryCacheforDatabaseQueries*/classQueryCache{private$cache;private$queryCacheTime;publicfunction__construct($cacheTime=60){$this->cache=newCacheManager();$this->queryCacheTime=$cacheTime;}/***Cachedatabasequery*/publicfunctioncacheQuery($sql,$params=[],$ttl=null){$key=$this->generateQueryKey($sql,$params);$ttl=$ttl??$this->queryCacheTime;return$this->cache->remember($key,function()use($sql,$params){/ThiswouldbecalledbyDatabaseclassreturn['sql'=>$sql,'params'=>$params];},$ttl);}/***Generatecachekeyforquery*/privatefunctiongenerateQueryKey($sql,$params){return'query_'.md5($sql.serialize($params));}/***Invalidatecachebytable*/publicfunctioninvalidateTable($table){return$this->cache->deletePattern($table);}/***Getcachestats*/publicfunctiongetStats(){return$this->cache->getStats();}}/***ApplicationCacheHelper*/classAppCache{privatestatic$instance=null;private$cache;privatefunction__construct(){$this->cache=newCacheManager();}publicstaticfunctiongetInstance(){if(self::$instance===null){self::$instance=newself();}returnself::$instance;}/***Cachepersonilstatistics*/publicfunctioncachePersonilStats($data,$ttl=300){return$this->cache->set('personil_stats',$data,$ttl);}/***Getcachedpersonilstatistics*/publicfunctiongetPersonilStats(){return$this->cache->get('personil_stats');}/***Cachedropdowndata*/publicfunctioncacheDropdownData($type,$data,$ttl=3600){return$this->cache->set("dropdown_{$type}",$data,$ttl);}/***Getcacheddropdowndata*/publicfunctiongetDropdownData($type){return$this->cache->get("dropdown_{$type}");}/***Clearallapplicationcache*/publicfunctionclearAll(){return$this->cache->clear();}/***Getcachestatistics*/publicfunctiongetStats(){return$this->cache->getStats();}}?>
